// Function to get evaluation material by subtopic name (case-insensitive)
function getEvaluationMaterial(subtopic) {
  if (!subtopic) return { evaluationDoc: null };
  const key = subtopic.trim().toLowerCase();
  const materials = evaluationMaterials[key];
  if (!materials) {
    return { evaluationDoc: null };
  }
  return materials;
}

// Get subtopic from input (from n8n input JSON)
const subtopicInput = $input.first().json.body.subtopic;

const result = getEvaluationMaterial(subtopicInput);

return [
  {
    json: {
      subtopic: subtopicInput,
      evaluationDocument: result.evaluationDoc
    }
  }
];

